// app/actions.ts
'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title')?.toString().trim();
  const body = formData.get('body')?.toString().trim();

  if (!title || !body) {
    throw new Error('Title and body are required');
  }

  await addPost(title, body);

  // Invalidate the "posts" cache tag with immediate expiration so the
  // next render fetches fresh data — no stale content is served.
  revalidateTag('posts', { expire: 0 });

  redirect('/');
}


// lib/posts.ts
import { unstable_cache } from 'next/cache';

export interface Post {
  id: number;
  title: string;
  body: string;
  createdAt: Date;
}

// In-memory store (a real app would use a database)
const store: Post[] = [
  { id: 1, title: 'Hello World', body: 'This is the first post.', createdAt: new Date() },
];

let nextId = 2;

const TAG = 'posts';

/** Fetch all posts, cached with the "posts" tag. */
export const getPosts = unstable_cache(
  async (): Promise<Post[]> => {
    // Simulate a slow data fetch to demonstrate cache behaviour
    await new Promise((r) => setTimeout(r, 500));
    return [...store].sort((a, b) => b.id - a.id);
  },
  ['posts-list'],
  { tags: [TAG] },
);

/** Insert a new post. Caller is responsible for cache invalidation. */
export async function addPost(title: string, body: string): Promise<Post> {
  const post: Post = {
    id: nextId++,
    title,
    body,
    createdAt: new Date(),
  };
  store.unshift(post);
  return post;
}


// app/page.tsx
import { getPosts } from '@/lib/posts';
import { createPost } from './actions';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: '2rem 1rem' }}>
      <h1>Posts</h1>

      <form action={createPost} style={{ marginBottom: '2rem', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
        <input
          name="title"
          placeholder="Title"
          required
          style={{ padding: '0.5rem', border: '1px solid #ccc', borderRadius: 4 }}
        />
        <textarea
          name="body"
          placeholder="Body"
          required
          rows={3}
          style={{ padding: '0.5rem', border: '1px solid #ccc', borderRadius: 4 }}
        />
        <button
          type="submit"
          style={{ padding: '0.5rem 1rem', background: '#0070f3', color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer' }}
        >
          Create Post
        </button>
      </form>

      {posts.length === 0 ? (
        <p>No posts yet.</p>
      ) : (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {posts.map((post) => (
            <li key={post.id} style={{ marginBottom: '1.5rem', borderBottom: '1px solid #eee', paddingBottom: '1rem' }}>
              <h2 style={{ margin: '0 0 0.25rem' }}>{post.title}</h2>
              <p style={{ margin: 0, color: '#555' }}>{post.body}</p>
              <small style={{ color: '#999' }}>{post.createdAt.toLocaleString()}</small>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}


